// QuerySLBAndExport executes:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]'
// and writes the formatted result to outputFile.
//
// It avoids invoking a shell and instead connects commands directly via pipes.
// The returned string is the final jq stdout content that is also written to the output file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

