	if dir := filepath.Dir(outputFile); dir != "." {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return "", fmt.Errorf("failed to create output directory: %w", err)
		}
	}

	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	jqCmd.Stdin = aliyunStdout

	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	var jqStdout bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr
	jqCmd.Stdout = ioMultiWriter(&jqStdout, outFile)

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		_ = aliyunCmd.Process.Kill()
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	result := jqStdout.String()

	if aliyunErr != nil {
		return result, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		return result, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	return result, nil
}

func ioMultiWriter(writers ...interface{ Write([]byte) (int, error) }) interface{ Write([]byte) (int, error) } {
	return multiWriter{writers: writers}
}

type multiWriter struct {
	writers []interface{ Write([]byte) (int, error) }
}

func (m multiWriter) Write(p []byte) (int, error) {
	for _, w := range m.writers {
