		if aliyunStderr.Len() > 0 {
			return "", fmt.Errorf("aliyun command failed: %w: %s", err, aliyunStderr.String())
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)

	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
