package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the equivalent of:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It returns the combined stderr/stdout execution details and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	var combinedOutput bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr
	jqCmd.Stdout = outFile

	pipeReader, pipeWriter := ioPipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	if err := jqCmd.Start(); err != nil {
		pipeReader.Close()
		pipeWriter.Close()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		pipeReader.Close()
		pipeWriter.Close()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	aliyunErr := aliyunCmd.Wait()
	_ = pipeWriter.Close()

	jqErr := jqCmd.Wait()
	_ = pipeReader.Close()

	if aliyunStderr.Len() > 0 {
		combinedOutput.WriteString("aliyun stderr:\n")
		combinedOutput.Write(aliyunStderr.Bytes())
		if aliyunStderr.Bytes()[aliyunStderr.Len()-1] != '\n' {
			combinedOutput.WriteByte('\n')
		}
	}

	if jqStderr.Len() > 0 {
		combinedOutput.WriteString("jq stderr:\n")
		combinedOutput.Write(jqStderr.Bytes())
		if jqStderr.Bytes()[jqStderr.Len()-1] != '\n' {
			combinedOutput.WriteByte('\n')
		}
	}

	if aliyunErr != nil {
		return combinedOutput.String(), fmt.Errorf("aliyun command failed: %w", aliyunErr)
	}
	if jqErr != nil {
		return combinedOutput.String(), fmt.Errorf("jq command failed: %w", jqErr)
	}

	if combinedOutput.Len() == 0 {
		combinedOutput.WriteString("command executed successfully")
	}

	return combinedOutput.String(), nil
}

// ioPipe wraps os.Pipe-compatible behavior for connecting command stdout/stdin.
func ioPipe() (*os.File, *os.File) {
	r, w, err := os.Pipe()
	if err != nil {
		panic(fmt.Sprintf("failed to create pipe: %v", err))
	}
	return r, w
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	result, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if result != "" {
		fmt.Println(result)
	}
	if err != nil {
		fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}
}

