package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]'
//
// It writes the jq output to outputFile and returns the command output content.
// Commands are executed without invoking a shell to avoid command injection risks.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	var aliyunErr bytes.Buffer
	var jqErr bytes.Buffer
	jqOutput := &bytes.Buffer{}

	pipeReader, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	aliyunCmd.Stderr = &aliyunErr
	jqCmd.Stdin = pipeReader
	jqCmd.Stdout = jqOutput
	jqCmd.Stderr = &jqErr

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	aliyunWaitErr := aliyunCmd.Wait()
	jqWaitErr := jqCmd.Wait()

	if aliyunWaitErr != nil {
		return jqOutput.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunWaitErr, aliyunErr.String())
	}

	if jqWaitErr != nil {
		return jqOutput.String(), fmt.Errorf("jq command failed: %w, stderr: %s", jqWaitErr, jqErr.String())
	}

	if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
		return jqOutput.String(), fmt.Errorf("failed to write output file: %w", err)
	}

	return jqOutput.String(), nil
}

