package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]'
// and writes the formatted result to outputFile.
//
// It avoids shell invocation and uses os/exec directly.
// The returned string is the jq stdout content that is also written to outputFile.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	loadBalancerName = strings.TrimSpace(loadBalancerName)
	outputFile = strings.TrimSpace(outputFile)

	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Ensure output directory exists if a directory is specified.
	if dir := filepath.Dir(outputFile); dir != "." && dir != "" {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return "", fmt.Errorf("failed to create output directory: %w", err)
		}
	}

	// First command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	var aliyunStderr bytes.Buffer
	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	pipeReader, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = pipeReader

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	if aliyunErr != nil {
		return jqStdout.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, strings.TrimSpace(aliyunStderr.String()))
	}

	if jqErr != nil {
		return jqStdout.String(), fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, strings.TrimSpace(jqStderr.String()))
	}

	result := jqStdout.String()

	if err := os.WriteFile(outputFile, []byte(result), 0o644); err != nil {
		return result, fmt.Errorf("failed to write output file: %w", err)
	}

	return result, nil
}

func main() {
	// Example usage:
	// result, err := QuerySLBAndExport("your-slb-name", "output.json")
	// if err != nil {
	// 	fmt.Println("Error:", err)
	// 	return
	// }
