// QuerySLBAndExport executes the aliyun CLI command safely without invoking a shell,
// processes the output with jq, and saves the result to the specified file.
// Returns jq stdout and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if err := validateLoadBalancerName(loadBalancerName); err != nil {
		return "", err
	}
	if err := validateOutputFile(outputFile); err != nil {
		return "", err
	}

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	var aliyunStderr bytes.Buffer
	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	outputHandle, err := os.OpenFile(outputFile, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o600)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outputHandle.Close()

	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipeline: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	aliyunErr := aliyunCmd.Wait()
	jqOutput := jqStdout.String()

	if _, writeErr := outputHandle.Write(jqStdout.Bytes()); writeErr != nil {
		_ = jqCmd.Wait()
		return jqOutput, fmt.Errorf("failed to write output file: %w", writeErr)
	}

	jqErr := jqCmd.Wait()

	if aliyunErr != nil {
		return jqOutput, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}

	if jqErr != nil {
		return jqOutput, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	return jqOutput, nil
}

var loadBalancerNamePattern = regexp.MustCompile(`^[a-zA-Z0-9._-]{1,128}$`)

func validateLoadBalancerName(name string) error {
	if !loadBalancerNamePattern.MatchString(name) {
