package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
)

var loadBalancerNamePattern = regexp.MustCompile(`^[A-Za-z0-9._-]{1,80}$`)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the jq stdout and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if !loadBalancerNamePattern.MatchString(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}
	if filepath.IsAbs(outputFile) {
		return "", fmt.Errorf("absolute output paths are not allowed")
	}
	if filepath.Clean(outputFile) != outputFile {
		return "", fmt.Errorf("invalid outputFile path")
	}

	outDir := filepath.Dir(outputFile)
	if outDir != "." {
		if err := os.MkdirAll(outDir, 0o755); err != nil {
			return "", fmt.Errorf("failed to create output directory: %w", err)
		}
	}

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStdout bytes.Buffer
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = &aliyunStderr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunStdout.Bytes())

	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0o600); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqStdout.String(), nil
}

func main() {
	result, err := QuerySLBAndExport("example-slb", "output.json")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(result)
}

