package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]'
//
// It writes the jq output to outputFile and returns the command output string.
// The implementation avoids shell invocation and uses os/exec directly.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Ensure parent directory exists if specified.
	if dir := filepath.Dir(outputFile); dir != "." {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return "", fmt.Errorf("failed to create output directory: %w", err)
		}
	}

	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	var resultBuf bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stdin = aliyunStdout
	jqCmd.Stderr = &jqStderr
	jqCmd.Stdout = io.MultiWriter(&resultBuf, outFile)

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	if aliyunErr != nil {
		return resultBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, strings.TrimSpace(aliyunStderr.String()))
	}

	if jqErr != nil {
		return resultBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, strings.TrimSpace(jqStderr.String()))
	}

	return resultBuf.String(), nil
}

