package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	var stderr bytes.Buffer
	var result bytes.Buffer

	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	jqCmd.Stdin = aliyunStdout
	jqCmd.Stdout = &result
	jqCmd.Stderr = &stderr
	aliyunCmd.Stderr = &stderr

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w; stderr: %s", err, stderr.String())
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w; stderr: %s", err, stderr.String())
	}

	if err := aliyunCmd.Wait(); err != nil {
		_ = jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w; stderr: %s", err, stderr.String())
	}

	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w; stderr: %s", err, stderr.String())
	}

	if err := os.WriteFile(outputFile, result.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return result.String(), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		return
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	output, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Println(output)
}

